def _docx_plain_text(path: Path) -> str:
 with zipfile.ZipFile(path, "r") as zf:
 xml = zf.read("word/document.xml")
 root = ET.fromstring(xml)
 parts: list[str] = []
 for t in root.iter("{http://schemas.openxmlformats.org/wordprocessingml/2006/main}t"):
 if t.text:
 parts.append(t.text)
 if t.tail:
 parts.append(t.tail)
 return " ".join(parts)

