def _parse_dt(value: Any) -> datetime | None:
 if value is None:
 return None
 text = str(value).strip()
 try:
 return datetime.fromisoformat(text.replace("Z", "+00:00"))
 except Exception:
 return None

def _item_dt(item: dict[str, Any], *keys: str) -> datetime | None:
 for key in keys:
