 diff_sum += abs(actual - exp) / 10.0
 accuracy = 1.0 - (diff_sum / len(expected)) if expected else 0.0
 trust_score = max(0.0, min(1.0, accuracy))
 checks.append({
 "id": "trust_assessment",
